// PStream class and its derived classes (will be managed on host)
class PStream {
public:
    virtual size_t read(float *dest, int dim, int num) = 0;
    virtual int ferror() = 0;
    virtual int feof() = 0;
    virtual ~PStream() {}
};

class SimStream : public PStream {
public:
    SimStream(long n_) : n(n_) {}
    size_t read(float *dest, int dim, int num) {
        size_t count = 0;
        for (int i = 0; i < num && n > 0; ++i) {
            for (int k = 0; k < dim; ++k) {
                dest[i * dim + k] = static_cast<float>(rand()) / RAND_MAX;
            }
            n--;
            count++;
        }
        return count;
    }
    int ferror() { return 0; }
    int feof() { return n <= 0; }
    ~SimStream() {}
private:
    long n;
};

class FileStream : public PStream {
public:
    FileStream(char *filename) {
        fp = fopen(filename, "rb");
        if (fp == NULL) {
            fprintf(stderr, "error opening file %s\n.", filename);
            exit(1);
        }
    }
    size_t read(float *dest, int dim, int num) {
        return fread(dest, sizeof(float) * dim, num, fp);
    }
    int ferror() { return ferror(fp); }
    int feof() { return feof(fp); }
