// Host function to initialize CUDA memory and launch kernels
void streamCluster_cuda(PStream *stream_host,
                        long kmin, long kmax, int dim,
                        long chunksize, long centersize, char *outfile) {

    kmin_global = kmin;
    kmax_global = kmax;
    dim_global = dim;
    chunksize_global = chunksize;
    centersize_global = centersize;
    strcpy(outfile_global, outfile);

    // Allocate host memory
    allocHostMem(chunksize, dim, centersize);

    // Initialize CUDA device
    int deviceCount;
    cudaGetDeviceCount(&deviceCount);
    if (deviceCount == 0) {
        fprintf(stderr, "No CUDA devices found!\n");
        return;
    }
    cudaSetDevice(0); // Use the first available device

    // Allocate device memory
    allocDevMem(chunksize, dim, centersize);

    // Initialize Points structures on host
    Points points_host;
    points_host.dim = dim;
    points_host.num = chunksize;
    points_host.p = (Point *)malloc(chunksize * sizeof(Point));
    for (int i = 0; i < chunksize; ++i) {
        points_host.p[i].coord = &d_block[i * dim];
    }

    Points centers_host;
    centers_host.dim = dim;
    centers_host.p = (Point *)malloc(centersize * sizeof(Point));
    centers_host.num = 0;
    for (int i = 0; i < centersize; ++i) {
        centers_host.p[i].coord = &d_centerBlock[i * dim];
        centers_host.p[i].weight = 1.0f;
    }

    // Copy host data to device
    CUDA_CHECK(cudaMemcpy(d_block_dev, d_block, chunksize * dim * sizeof(float), cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_centerBlock_dev, d_centerBlock, centersize * dim * sizeof(float), cudaMemcpyHostToDevice));

    // Setup d_points and d_centers on device
    d_points.dim = dim;
    d_points.num = chunksize;
    d_points.p = d_points_p_dev;
    CUDA_CHECK(cudaMemcpyToSymbol(d_points, &d_points, sizeof(Points)));

    d_centers.dim = dim;
    d_centers.num = 0;
    d_centers.p = d_centers_p_dev;
    CUDA_CHECK(cudaMemcpyToSymbol(d_centers, &d_centers, sizeof(Points)));

    // Copy point data for initial chunk
    CUDA_CHECK(cudaMemcpy(d_points_p_dev, points_host.p, chunksize * sizeof(Point), cudaMemcpyHostToDevice));
    for (int i = 0; i < chunksize; ++i) {
        d_points.p[i].coord = d_block_dev + i * dim; // Update coord pointers on device
    }
    CUDA_CHECK(cudaMemcpy(d_points_p_dev, &d_points, sizeof(Point) * chunksize, cudaMemcpyHostToDevice));

    // Copy center data for initial centers
    CUDA_CHECK(cudaMemcpy(d_centers_p_dev, centers_host.p, centersize * sizeof(Point), cudaMemcpyHostToDevice));
    for (int i = 0; i < centersize; ++i) {
        d_centers.p[i].coord = d_centerBlock_dev + i * dim; // Update coord pointers on device
    }
    CUDA_CHECK(cudaMemcpy(d_centers_p_dev, &d_centers, sizeof(Point) * centersize, cudaMemcpyHostToDevice));

    // Global pointers for kernels
    d_switch_membership = d_switch_membership_dev;
    d_is_center = d_is_center_dev;
    d_center_table = d_center_table_dev;

    long IDoffset = 0;
    long kfinal = 0;

    while (1) {
        size_t numRead = stream_host->read(d_block, dim, chunksize);
        fprintf(stderr, "read %zu points\n", numRead);

        if (stream_host->ferror() || (numRead < (size_t)chunksize && !stream_host->feof())) {
            fprintf(stderr, "error reading data!\n");
            exit(1);
        }

        // Update points.num on device
        d_points.num = numRead;
        CUDA_CHECK(cudaMemcpyToSymbol(d_points, &d_points, sizeof(Points)));

        // Update point weights on device
        for (int i = 0; i < numRead; ++i) {
            d_points.p[i].weight = 1.0f;
        }
        CUDA_CHECK(cudaMemcpy(d_points_p_dev, &d_points, sizeof(Point) * numRead, cudaMemcpyHostToDevice));

        // Allocate and initialize device memory for current chunk
        CUDA_CHECK(cudaMalloc(&d_switch_membership_dev, numRead * sizeof(bool)));
        CUDA_CHECK(cudaMemset(d_switch_membership_dev, 0, numRead * sizeof(bool)));
        CUDA_CHECK(cudaMalloc(&d_is_center_dev, numRead * sizeof(bool)));
        CUDA_CHECK(cudaMemset(d_is_center_dev, 0, numRead * sizeof(bool)));
        CUDA_CHECK(cudaMalloc(&d_center_table_dev, numRead * sizeof(int)));

        // Call localSearch on device
        streamCluster_kernel<<<1, 1>>>(kmin, kmax, dim, chunksize, centersize, outfile, numRead);
        CUDA_CHECK(cudaGetLastError());
        CUDA_CHECK(cudaDeviceSynchronize());

        // contcenters(&points);
        contcenters_kernel<<< (numRead + 255) / 256, 256 >>>(&d_points, numRead);
        CUDA_CHECK(cudaGetLastError());
        CUDA_CHECK(cudaDeviceSynchronize());

        // copycenters(&points, &centers, centerIDs, IDoffset);
        copycenters_kernel<<<1, 1>>>( &d_points, &d_centers, d_centerIDs_dev, IDoffset, numRead);
        CUDA_CHECK(cudaGetLastError());
        CUDA_CHECK(cudaDeviceSynchronize());

        // Update centers.num on device (assuming copycenters_kernel does this)
        // Need to read back d_centers.num after copycenters_kernel completes.
        CUDA_CHECK(cudaMemcpyFromSymbol(&d_centers, d_centers, sizeof(Points)));


        // Free temporary device memory for the current chunk
        CUDA_CHECK(cudaFree(d_switch_membership_dev));
        CUDA_CHECK(cudaFree(d_is_center_dev));
        CUDA_CHECK(cudaFree(d_center_table_dev));
        d_switch_membership_dev = NULL;
        d_is_center_dev = NULL;
        d_center_table_dev = NULL;


        if (stream_host->feof()) {
            break;
        }
    }

    // Finally cluster all temp centers
    // Allocate device memory for final clustering
    CUDA_CHECK(cudaMalloc(&d_switch_membership_dev, d_centers.num * sizeof(bool)));
    CUDA_CHECK(cudaMemset(d_switch_membership_dev, 0, d_centers.num * sizeof(bool)));
    CUDA_CHECK(cudaMalloc(&d_is_center_dev, d_centers.num * sizeof(bool)));
    CUDA_CHECK(cudaMemset(d_is_center_dev, 0, d_centers.num * sizeof(bool)));
    CUDA_CHECK(cudaMalloc(&d_center_table_dev, d_centers.num * sizeof(int)));

    // Call localSearch on device for final clustering
    streamCluster_kernel<<<1, 1>>>(kmin, kmax, dim, chunksize, centersize, outfile, d_centers.num);
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    // contcenters(&centers);
    contcenters_kernel<<< (d_centers.num + 255) / 256, 256 >>>(&d_centers, d_centers.num);
    CUDA_CHECK(cudaGetLastError());
    CUDA_CHECK(cudaDeviceSynchronize());

    // outcenterIDs( &centers, centerIDs, outfile);
    // Copy final centers and IDs back to host
    CUDA_CHECK(cudaMemcpy(centers_host.p, d_centers_p_dev, d_centers.num * sizeof(Point), cudaMemcpyDeviceToHost));
    CUDA_CHECK(cudaMemcpy(d_centerIDs, d_centerIDs_dev, d_centers.num * sizeof(long), cudaMemcpyDeviceToHost));

    // Host-side file writing for outcenterIDs
    FILE *fp = fopen(outfile, "w");
    if (fp == NULL) {
        fprintf(stderr, "error opening %s\n", outfile);
        exit(1);
    }
    bool *is_a_median_host = (bool *)calloc(centers_host.num, sizeof(bool));
    for (int i = 0; i < d_centers.num; ++i) { // Use d_centers.num which is the actual number of centers
        if (centers_host.p[i].assign < d_centers.num) { // Check bounds
             is_a_median_host[centers_host.p[i].assign] = true;
        }
    }

    for (int i = 0; i < d_centers.num; ++i) {
        if (is_a_median_host[i]) {
            fprintf(fp, "%lu\n", d_centerIDs[i]);
            fprintf(fp, "%lf\n", centers_host.p[i].weight);
            for (int k = 0; k < centers_host.dim; ++k) {
                fprintf(fp, "%lf ", centers_host.p[i].coord[k]);
            }
            fprintf(fp, "\n\n");
        }
    }
    fclose(fp);
    free(is_a_median_host);

    // Free device memory
    freeDevMem();

    // Free host memory
    freeHostMem();

    // Free host Point arrays
    free(points_host.p);
    free(centers_host.p);
}

